QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
                                           const qemu_info_t *info,
                                           int argc, char **argv)
{
    (void) info;
    for (int i = 0; i < argc; i++) {
        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
            outfile_path = g_strdup(tok[1]);
        } else if (g_strcmp0(tok[0], "enter_pc") == 0 && tok[1]) {
            char *endp = NULL;
            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
            if (!endp || *endp != '\0') {
                fprintf(stderr, "hybrid_handoff: invalid enter_pc=%s\n",
                        tok[1]);
                return -1;
            }
            enter_pc_arg = (uint64_t) v;
            pc_mode = 1;
        } else if (g_strcmp0(tok[0], "icount") == 0 && tok[1]) {
            char *endp = NULL;
            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
            if (!endp || *endp != '\0' || v == 0) {
                fprintf(stderr, "hybrid_handoff: invalid icount=%s\n",
                        tok[1]);
                return -1;
            }
            icount_target = (uint64_t) v;
            icount_mode = 1;
        } else if (g_strcmp0(tok[0], "bbv_out") == 0 && tok[1]) {
            bbv_out_path = g_strdup(tok[1]);
            bbv_mode = 1;
        } else if (g_strcmp0(tok[0], "slice") == 0 && tok[1]) {
            char *endp = NULL;
            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
            if (!endp || *endp != '\0' || v == 0) {
                fprintf(stderr, "hybrid_handoff: invalid slice=%s\n",
                        tok[1]);
                return -1;
            }
            bbv_slice_target = (uint64_t) v;
        } else if (g_strcmp0(tok[0], "slice_at") == 0 && tok[1]) {
            char *endp = NULL;
            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
            if (!endp || *endp != '\0') {
                fprintf(stderr, "hybrid_handoff: invalid slice_at=%s\n",
                        tok[1]);
                return -1;
            }
            slice_at_target = (uint64_t) v;
            slice_consume_mode = 1;
        } else {
            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
            return -1;
        }
    }
    if (!outfile_path) {
        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
        return -1;
    }
    if (pc_mode) {
        fprintf(stderr,
                "hybrid_handoff: PC-mode enter=0x%" PRIx64 "\n",
                enter_pc_arg);
    }
    if (icount_mode) {
        fprintf(stderr,
                "hybrid_handoff: icount-mode target=%" PRIu64 "\n",
                icount_target);
    }
    if (bbv_mode) {
        if (bbv_slice_target == 0) {
            fputs("hybrid_handoff: bbv_out= requires slice=N\n", stderr);
            return -1;
        }
        bbv_emit = bbv_emit_new(bbv_out_path, bbv_slice_target);
        if (!bbv_emit) {
            fprintf(stderr, "hybrid_handoff: failed to open bbv_out=%s\n",
                    bbv_out_path);
            return -1;
        }
        fprintf(stderr,
                "hybrid_handoff: bbv-mode out=%s slice=%" PRIu64 "\n",
                bbv_out_path, bbv_slice_target);
    }
    if (slice_consume_mode) {
        if (bbv_slice_target == 0) {
            fputs("hybrid_handoff: slice_at= requires slice=N\n", stderr);
            return -1;
        }
        fprintf(stderr,
                "hybrid_handoff: slice-consume mode slice=%" PRIu64
                " slice_at=%" PRIu64 "\n",
                bbv_slice_target, slice_at_target);
    }

    vcpu_state = qemu_plugin_scoreboard_new(sizeof(VcpuRegs));
    qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);
    return 0;
}

