def _qemu_profile_argv(qemu: Path, elf: Path, plugin: Path,
                       shm_path: Path, shm_size: int, state_out: Path,
                       bbv_out: Path, slice_n: int, icount: int) -> list[str]:
    """M4 profile pass argv: `_qemu_drain_argv` + the BBV plugin extras."""
    return _qemu_drain_argv(
        qemu, elf, plugin, shm_path, shm_size, state_out,
        plugin_extras=(
            f"bbv_out={bbv_out}",
            f"slice={slice_n}",
            f"icount={icount}",
        ),
    )


def cmd_profile(args: argparse.Namespace) -> int:
    elf = Path(args.elf)
    if not elf.is_absolute():
        elf = (Path.cwd() / elf).resolve()
    if not elf.is_file():
        print(f"hsim: ELF not found: {args.elf}", file=sys.stderr)
        return 2

    artifacts = _resolve_artifacts()
    # Profile pass uses qemu + plugin only; vsim is not invoked.
    for label in ("qemu", "plugin"):
        if not artifacts[label].is_file():
            print(f"hsim: {label} not built -- run ./hsim build",
                  file=sys.stderr)
            return 2

    bbv = Path(args.output)
    bbv.parent.mkdir(parents=True, exist_ok=True)

    try:
        shm_path = _load_hsim_shm().allocate(
            args.mmap_size, prefix="hsim-profile-shm.",
        )
    except Exception as exc:
        print(f"hsim: {exc}", file=sys.stderr)
        return 2

    state_fd, state_name = tempfile.mkstemp(prefix="hsim-profile-state.")
    os.close(state_fd)
    state_out = Path(state_name)

    try:
        argv = _qemu_profile_argv(
            qemu=artifacts["qemu"], elf=elf, plugin=artifacts["plugin"],
            shm_path=shm_path, shm_size=args.mmap_size, state_out=state_out,
            bbv_out=bbv, slice_n=args.slice, icount=args.icount,
        )

        if args.dry_run:
            print(f"exec: {shlex.join(argv)}")
            return 0

        proc = subprocess.run(
            argv, cwd=REPO_ROOT,
            stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
            timeout=_PROFILE_TIMEOUT_S,
        )
        if proc.returncode != _QEMU_DRAIN_RC:
            tail = proc.stdout.decode("utf-8", "replace").splitlines()[-20:]
            print(f"hsim: QEMU profile expected exit {_QEMU_DRAIN_RC}, "
                  f"got {proc.returncode}", file=sys.stderr)
            for line in tail:
                print(line, file=sys.stderr)
            return 1

        if not bbv.is_file() or bbv.stat().st_size == 0:
            print(f"hsim: profile produced empty BBV: {bbv}", file=sys.stderr)
            return 1
        rows = sum(1 for _ in bbv.open())
        print(f"profile: {rows} BBV rows -> {bbv}")
        return 0
    finally:
        for p in (shm_path, state_out):
            try:
                p.unlink()
            except FileNotFoundError:
                pass


