    size_t n = qemu_plugin_tb_n_insns(tb);

    // BBV-mode: assign a stable bb_id to this TB (1-based, hashed by
    // TB-start vaddr). Same id is shared by every insn in the TB.
    uint64_t bb_id = 0;
